sql:
SELECT metric_name, metric_value
FROM widget_metrics
WHERE widget_id = 1 AND metric_date = '2023-06-01';

external_knowledge:
; 
; 'top-performing' refers to the campaigns with the highest total metric values within the given timeframe; 
; 'last year' refers to the year 2023, as specified in the metric date range; 
; 'positive results' are indicated by a total metric value greater than 0.
